const raw = $input.all()[0]?.json ?? {};
let payload = raw.query ?? raw;
let parseError = false;

if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    payload = {};
    parseError = true;
  }
}

if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
  payload = {};
  parseError = true;
}

const registry = {
  // Example for later configuration:
  // research_bot: {
  //   displayName: 'Research Bot',
  //   enabled: true,
  //   transport: 'webhook',
  //   webhookUrl: 'https://example.com/webhook',
  //   allowedActions: ['research', 'check'],
  //   privacyLevel: 'minimal'
  // }
};

function str(value) {
  return String(value ?? '').trim();
}

const truncation = { any: false };

function clip(value, maxLength) {
  const text = str(value);
  if (text.length > maxLength) truncation.any = true;
  return text.slice(0, maxLength);
}

function finish({ ok, output, data = {}, error = null, status = ok ? 'sent' : 'failed' }) {
  return [{
    json: {
      ok,
      action: 'dispatch_task',
      version: 'v1',
      status,
      data,
      error,
      meta: {
        correlationId: data.correlationId || str(payload.correlationId),
        registrySize: Object.keys(registry).length,
        truncated: truncation.any,
      },
      output,
    },
  }];
}

if (parseError) {
  return finish({
    ok: false,
    output: 'bot_task_tools 参数不是有效 JSON。',
    error: { code: 'INVALID_TOOL_INPUT', message: '参数不是有效 JSON。', retryable: false },
  });
}

const action = str(payload.action || payload.operation || payload.tool || 'dispatch_task');
if (action !== 'dispatch_task') {
  return finish({
    ok: false,
    output: 'bot_task_tools 不支持 action：' + (action || '(空)') + '。当前支持：dispatch_task。',
    error: { code: 'UNSUPPORTED_ACTION', message: 'Unsupported action: ' + action, retryable: false },
  });
}

const directDestinationFields = [
  'chatId',
  'chat_id',
  'webhookUrl',
  'webhook_url',
  'url',
  'destination',
  'endpoint',
  'receive_id',
  'receiveId',
  'open_id',
  'openId',
];
const directDestinationField = directDestinationFields.find((field) => str(payload[field]));
if (directDestinationField) {
  return finish({
    ok: false,
    output: '派发失败：不能在参数里直接指定目标字段 ' + directDestinationField + '；请先把机器人加入 registry。',
    error: { code: 'DIRECT_DESTINATION_FORBIDDEN', message: 'Destination must be resolved from registry.', retryable: false },
  });
}

const botKey = clip(payload.botKey || payload.botName || payload.bot || payload.targetBot, 128);
const taskType = clip(payload.taskType || payload.allowedAction || payload.type || 'other', 64);
const prompt = clip(payload.prompt || payload.task || payload.instruction, 1000);
const expectedOutput = clip(payload.expectedOutput || payload.expected_output || '', 500);
const correlationId = clip(payload.correlationId || payload.correlation_id || ('oar-' + Date.now()), 128);
const ttlSecondsRaw = Number(payload.ttlSeconds ?? payload.ttl_seconds ?? 900);
const ttlSeconds = Number.isFinite(ttlSecondsRaw) ? Math.min(Math.max(Math.trunc(ttlSecondsRaw), 60), 3600) : 900;
const contextSource = payload.minimalContext ?? payload.context ?? {};
const context = typeof contextSource === 'object' && contextSource && !Array.isArray(contextSource)
  ? contextSource
  : { summary: str(contextSource) };
const summary = clip(context.summary, 1000);
const allowedFields = Array.isArray(context.allowedFields)
  ? context.allowedFields.map((field) => clip(field, 100)).filter(Boolean).slice(0, 20)
  : [];

if (!botKey) {
  return finish({
    ok: false,
    output: '派发失败：缺少 botKey。',
    error: { code: 'MISSING_BOT_KEY', message: 'botKey is required.', retryable: false },
  });
}

if (!prompt) {
  return finish({
    ok: false,
    output: '派发失败：缺少 task/prompt。',
    error: { code: 'MISSING_TASK', message: 'task or prompt is required.', retryable: false },
  });
}

const bot = registry[botKey];
if (!bot) {
  return finish({
    ok: false,
    status: 'not_configured',
    output: '派发失败：机器人 ' + botKey + ' 尚未配置。请先在 OAR Bot Task Tools 的 registry 中加入该机器人。',
    data: { botKey, taskType, correlationId },
    error: { code: 'BOT_NOT_CONFIGURED', message: 'Bot is not configured: ' + botKey, retryable: false },
  });
}

if (bot.enabled !== true) {
  return finish({
    ok: false,
    status: 'disabled',
    output: '派发失败：机器人 ' + (bot.displayName || botKey) + ' 当前未启用。',
    data: { botKey, taskType, correlationId },
    error: { code: 'BOT_DISABLED', message: 'Bot is disabled: ' + botKey, retryable: false },
  });
}

const allowedActions = Array.isArray(bot.allowedActions) ? bot.allowedActions : [];
if (!allowedActions.includes(taskType)) {
  return finish({
    ok: false,
    status: 'not_allowed',
    output: '派发失败：机器人 ' + (bot.displayName || botKey) + ' 不允许执行任务类型 ' + taskType + '。',
    data: { botKey, taskType, allowedActions, correlationId },
    error: { code: 'BOT_ACTION_NOT_ALLOWED', message: 'Task type is not allowed for bot.', retryable: false },
  });
}

const dispatchBody = {
  source: 'OAR',
  botKey,
  taskType,
  prompt,
  context: { summary, allowedFields },
  expectedOutput,
  correlationId,
  ttlSeconds,
};

if (bot.transport !== 'webhook' || !bot.webhookUrl) {
  return finish({
    ok: false,
    status: 'not_configured',
    output: '派发失败：机器人 ' + (bot.displayName || botKey) + ' 缺少可用 webhook 配置。',
    data: { botKey, taskType, correlationId, sentSummary: summary },
    error: { code: 'BOT_DESTINATION_NOT_CONFIGURED', message: 'Webhook destination missing.', retryable: false },
  });
}

try {
  const response = await $helpers.httpRequest({
    method: 'POST',
    url: bot.webhookUrl,
    body: dispatchBody,
    json: true,
    timeout: 20000,
  });
  return finish({
    ok: true,
    status: 'sent',
    output: '已向 ' + (bot.displayName || botKey) + ' 派发任务。',
    data: {
      botKey,
      botDisplayName: bot.displayName || botKey,
      taskType,
      correlationId,
      sentSummary: summary,
      expectedOutput,
      responseSummary: typeof response === 'string' ? response.slice(0, 1000) : JSON.stringify(response).slice(0, 1000),
    },
  });
} catch (error) {
  return finish({
    ok: false,
    status: 'failed',
    output: '派发失败：' + (error.message || String(error)),
    data: { botKey, taskType, correlationId, sentSummary: summary },
    error: { code: 'DISPATCH_HTTP_FAILED', message: error.message || String(error), retryable: true },
  });
}
